131: async function listEvents(count = 10) {
132: 	await db.init();
133: 	const eventData = await events.getEvents('', 0, count - 1);
134: 	console.log(chalk.bold(`\nDisplaying last ${count} administrative events...`));
135: 	eventData.forEach((event) => {
136: 		console.log(`  * ${chalk.green(String(event.timestampISO))} ${chalk.yellow(String(event.type))}${event.text ? ` ${event.text}` : ''} (uid: ${event.uid ? event.uid : 0})`);
