3: const path = require('path');
4: const winston = require('winston');
5: const fs = require('fs');
6: const chalk = require('chalk');
7: const nconf = require('nconf');
8: 
9: const db = require('../database');
10: const events = require('../events');
11: const meta = require('../meta');
12: const plugins = require('../plugins');
13: const widgets = require('../widgets');
14: const privileges = require('../privileges');
15: const { paths, pluginNamePattern, themeNamePattern } = require('../constants');
16: 
17: exports.reset = async function (options) {
18: 	const map = {
19: 		theme: async function () {
20: 			let themeId = options.theme;
21: 			if (themeId === true) {
22: 				await resetThemes();
23: 			} else {
24: 				if (!themeNamePattern.test(themeId)) {
25: 					// Allow omission of `nodebb-theme-`
26: 					themeId = `nodebb-theme-${themeId}`;
27: 				}
28: 
29: 				themeId = await plugins.autocomplete(themeId);
30: 				await resetTheme(themeId);
31: 			}
32: 		},
33: 		plugin: async function () {
34: 			let pluginId = options.plugin;
35: 			if (pluginId === true) {
36: 				await resetPlugins();
37: 			} else {
38: 				if (!pluginNamePattern.test(pluginId)) {
39: 					// Allow omission of `nodebb-plugin-`
40: 					pluginId = `nodebb-plugin-${pluginId}`;
41: 				}
42: 
43: 				pluginId = await plugins.autocomplete(pluginId);
44: 				await resetPlugin(pluginId);
45: 			}
46: 		},
47: 		widgets: resetWidgets,
48: 		settings: resetSettings,
49: 		all: async function () {
50: 			await resetWidgets();
51: 			await resetThemes();
52: 			await resetPlugin();
53: 			await resetSettings();
54: 		},
55: 	};
56: 
57: 	const tasks = Object.keys(map).filter(x => options[x]).map(x => map[x]);
58: 
59: 	if (!tasks.length) {
60: 		console.log([
61: 			chalk.yellow('No arguments passed in, so nothing was reset.\n'),
62: 			`Use ./nodebb reset ${chalk.red('{-t|-p|-w|-s|-a}')}`,
63: 			'    -t\tthemes',
64: 			'    -p\tplugins',
65: 			'    -w\twidgets',
66: 			'    -s\tsettings',
67: 			'    -a\tall of the above',
68: 			'',
69: 			'Plugin and theme reset flags (-p & -t) can take a single argument',
70: 			'    e.g. ./nodebb reset -p nodebb-plugin-mentions, ./nodebb reset -t nodebb-theme-harmony',
71: 			'         Prefix is optional, e.g. ./nodebb reset -p markdown, ./nodebb reset -t harmony',
72: 		].join('\n'));
73: 
74: 		process.exit(0);
75: 	}
76: 
77: 	try {
78: 		await db.init();
79: 		for (const task of tasks) {
80: 			/* eslint-disable no-await-in-loop */
81: 			await task();
82: 		}
83: 		winston.info('[reset] Reset complete. Please run `./nodebb build` to rebuild assets.');
84: 		process.exit(0);
85: 	} catch (err) {
86: 		winston.error(`[reset] Errors were encountered during reset -- ${err.message}`);
87: 		process.exit(1);
88: 	}
89: };
90: 
91: async function resetSettings() {
92: 	await privileges.global.give(['groups:local:login'], 'registered-users');
93: 	winston.info('[reset] registered-users given login privilege');
94: 	winston.info('[reset] Settings reset to default');
95: }
96: 
97: async function resetTheme(themeId) {
98: 	try {
99: 		await fs.promises.access(path.join(paths.nodeModules, themeId, 'package.json'));
100: 	} catch (err) {
101: 		winston.warn('[reset] Theme `%s` is not installed on this forum', themeId);
102: 		throw new Error('theme-not-found');
103: 	}
104: 	await resetThemeTo(themeId);
105: }
106: 
107: async function resetThemes() {
108: 	await resetThemeTo('nodebb-theme-harmony');
109: }
110: 
111: async function resetThemeTo(themeId) {
112: 	await meta.themes.set({
113: 		type: 'local',
114: 		id: themeId,
115: 	});
116: 	await meta.configs.set('bootswatchSkin', '');
117: 	winston.info(`[reset] Theme reset to ${themeId} and default skin`);
118: }
119: 
120: async function resetPlugin(pluginId) {
121: 	try {
122: 		if (nconf.get('plugins:active')) {
123: 			winston.error('Cannot reset plugins while plugin state is set in the configuration (config.json, environmental variables or terminal arguments), please modify the configuration instead');
124: 			process.exit(1);
125: 		}
126: 		const isActive = await db.isSortedSetMember('plugins:active', pluginId);
127: 		if (isActive) {
128: 			await db.sortedSetRemove('plugins:active', pluginId);
129: 			await events.log({
130: 				type: 'plugin-deactivate',
131: 				text: pluginId,
132: 			});
133: 			winston.info('[reset] Plugin `%s` disabled', pluginId);
134: 		} else {
135: 			winston.warn('[reset] Plugin `%s` was not active on this forum', pluginId);
136: 			winston.info('[reset] No action taken.');
137: 		}
138: 	} catch (err) {
139: 		winston.error(`[reset] Could not disable plugin: ${pluginId} encountered error %s\n${err.stack}`);
140: 		throw err;
141: 	}
142: }
143: 
144: async function resetPlugins() {
145: 	if (nconf.get('plugins:active')) {
146: 		winston.error('Cannot reset plugins while plugin state is set in the configuration (config.json, environmental variables or terminal arguments), please modify the configuration instead');
147: 		process.exit(1);
148: 	}
149: 	await db.delete('plugins:active');
150: 	winston.info('[reset] All Plugins De-activated');
151: }
152: 
153: async function resetWidgets() {
154: 	await plugins.reload();
155: 	await widgets.reset();
156: 	winston.info('[reset] All Widgets moved to Draft Zone');
157: }
