{"content":"1: 'use strict';
2: 
3: const winston = require('winston');
4: const path = require('path');
5: const fs = require('fs').promises;
6: const nconf = require('nconf');
7: const os = require('os');
8: const cproc = require('child_process');
9: const util = require('util');
10: 
11: const request = require('../request');
12: const db = require('../database');
13: const meta = require('../meta');
14: const pubsub = require('../pubsub');
15: const { paths, pluginNamePattern } = require('../constants');
16: const pkgInstall = require('../cli/package-install');
17: 
18: const packageManager = pkgInstall.getPackageManager();
19: let packageManagerExecutable = packageManager;
20: const packageManagerCommands = {
21: 	yarn: {
22: 		install: 'add',
23: 		uninstall: 'remove',
24: 	},
25: 	npm: {
26: 		install: 'install',
27: 		uninstall: 'uninstall',
28: 	},
29: 	cnpm: {
30: 		install: 'install',
31: 		uninstall: 'uninstall',
32: 	},
33: 	pnpm: {
34: 		install: 'install',
35: 		uninstall: 'uninstall',
36: 	},
37: };
38: 
39: if (process.platform === 'win32') {
40: 	packageManagerExecutable += '.cmd';
41: }
42: 
43: module.exports = function (Plugins) {
44: 	if (nconf.get('isPrimary')) {
45: 		pubsub.on('plugins:toggleInstall', (data) => {
46: 			if (data.hostname !== os.hostname()) {
47: 				toggleInstall(data.id, data.version);
48: 			}
49: 		});
50: 
51: 		pubsub.on('plugins:upgrade', (data) => {
52: 			if (data.hostname !== os.hostname()) {
53: 				upgrade(data.id, data.version);
54: 			}
55: 		});
56: 	}
57: 
58: 	Plugins.toggleActive = async function (id) {
59: 		if (nconf.get('plugins:active')) {
60: 			winston.error('Cannot activate plugins while plugin state is set in the configuration (config.json, environmental variables or terminal arguments), please modify the configuration instead');
61: 			throw new Error('[[error:plugins-set-in-configuration]]');
62: 		}
63: 		if (!pluginNamePattern.test(id)) {
64: 			throw new Error('[[error:invalid-plugin-id]]');
65: 		}
66: 		const isActive = await Plugins.isActive(id);
67: 		if (isActive) {
68: 			await db.sortedSetRemove('plugins:active', id);
69: 		} else {
70: 			const count = await db.sortedSetCard('plugins:active');
71: 			await db.sortedSetAdd('plugins:active', count, id);
72: 		}
73: 		meta.reloadRequired = true;
74: 		const hook = isActive ? 'deactivate' : 'activate';
75: 		Plugins.hooks.fire(`action:plugin.${hook}`, { id: id });
76: 		return { id: id, active: !isActive };
77: 	};
78: 
79: 	Plugins.checkWhitelist = async function (id, version) {
80: 		const { response, body } = await request.get(`https://packages.nodebb.org/api/v1/plugins/${encodeURIComponent(id)}`);
81: 		if (!response.ok) {
82: 			throw new Error(`[[error:cant-connect-to-nbbpm]]`);
83: 		}
84: 		if (body && body.code === 'ok' && (version === 'latest' || body.payload.valid.includes(version))) {
85: 			return;
86: 		}
87: 
88: 		throw new Error('[[error:plugin-not-whitelisted]]');
89: 	};
90: 
91: 	Plugins.suggest = async function (pluginId, nbbVersion) {
92: 		const { response, body } = await request.get(`https://packages.nodebb.org/api/v1/suggest?package=${encodeURIComponent(pluginId)}&version=${encodeURIComponent(nbbVersion)}`);
93: 		if (!response.ok) {
94: 			throw new Error(`[[error:cant-connect-to-nbbpm]]`);
95: 		}
96: 		return body;
97: 	};
98: 
99: 	Plugins.toggleInstall = async function (id, version) {
100: 		pubsub.publish('plugins:toggleInstall', { hostname: os.hostname(), id: id, version: version });
101: 		return await toggleInstall(id, version);
102: 	};
103: 
104: 	const runPackageManagerCommandAsync = util.promisify(runPackageManagerCommand);
105: 
106: 	async function toggleInstall(id, version) {
107: 		const [installed, active] = await Promise.all([
108: 			Plugins.isInstalled(id),
109: 			Plugins.isActive(id),
110: 		]);
111: 		const type = installed ? 'uninstall' : 'install';
112: 		if (active && !nconf.get('plugins:active')) {
113: 			await Plugins.toggleActive(id);
114: 		}
115: 		await runPackageManagerCommandAsync(type, id, version || 'latest');
116: 		const pluginData = await Plugins.get(id);
117: 		Plugins.hooks.fire(`action:plugin.${type}`, { id: id, version: version });
118: 		return pluginData;
119: 	}
120: 
121: 	function runPackageManagerCommand(command, pkgName, version, callback) {
122: 		cproc.execFile(packageManagerExecutable, [
123: 			packageManagerCommands[packageManager][command],
124: 			pkgName + (command === 'install' && version ? `@${version}` : ''),
125: 			'--save',
126: 		], (err, stdout) => {
127: 			if (err) {
128: 				return callback(err);
129: 			}
130: 
131: 			winston.verbose(`[plugins/${command}] ${stdout}`);
132: 			callback();
133: 		});
134: 	}
135: 
136: 
137: 	Plugins.upgrade = async function (id, version) {
138: 		pubsub.publish('plugins:upgrade', { hostname: os.hostname(), id: id, version: version });
139: 		return await upgrade(id, version);
140: 	};
141: 
142: 	async function upgrade(id, version) {
143: 		await runPackageManagerCommandAsync('install', id, version || 'latest');
144: 		const isActive = await Plugins.isActive(id);
145: 		meta.reloadRequired = isActive;
146: 		return isActive;
147: 	}
148: 
